### Logging/Tracing Requirements

```rust
use tracing::{debug, info, warn, error, instrument, Span};

impl McpContext {
    #[instrument(
        level = "debug",
        skip(self, args),
        fields(
            tool = %name,
            depth = self.inner.tool_call_depth,
            args_size = args.to_string().len()
        )
    )]
    pub async fn call_tool(&self, name: &str, args: Value) -> McpResult<CallToolResult> {
        debug!("Calling tool from handler context");

        if self.inner.tool_call_depth >= MAX_TOOL_CALL_DEPTH {
            warn!(
                depth = self.inner.tool_call_depth,
                max = MAX_TOOL_CALL_DEPTH,
                tool = %name,
                "Tool call depth limit exceeded - possible infinite recursion"
            );
            return Err(McpError::internal(format!(
                "Maximum tool call depth ({}) exceeded calling '{}' - possible infinite recursion",
                MAX_TOOL_CALL_DEPTH, name
            )));
        }

        let router = self.inner.router.as_ref()
            .ok_or_else(|| {
                warn!("Attempted to call tool without router in context");
                McpError::internal("No router available in context")
            })?;

        let child_ctx = self.with_incremented_tool_depth();
        debug!(new_depth = child_ctx.inner.tool_call_depth, "Created child context for tool call");

        let start = std::time::Instant::now();
        let result = router.call_tool(&child_ctx, name, args).await;
        let elapsed = start.elapsed();

        match &result {
            Ok(r) => debug!(
                is_error = r.is_error,
                elapsed_ms = elapsed.as_millis(),
                "Tool call completed"
            ),
            Err(e) => debug!(
                error = %e,
                elapsed_ms = elapsed.as_millis(),
                "Tool call failed"
            ),
        }

        result
    }
}
```

